  font-size: 0.78rem;
  font-weight: 700;
  cursor: pointer;
}

.workspace-state {
  margin-left: 0.6rem;
  font-size: 0.8rem;
  font-weight: 600;
  color: var(--muted-foreground);
}

.pending-file {
  display: inline-flex;
  align-items: center;
  gap: 0.45rem;
  font-size: 0.8rem;
}

.pending-file button {
  border: 1px solid var(--border);
  border-radius: 0;
  background: var(--card);
  color: var(--foreground);
  cursor: pointer;
  padding: 0.2rem 0.45rem;
}

.onboarding-action-buttons {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  padding: 0.1rem 0.1rem 0.2rem;
}

.onboarding-action-buttons button {
  border: 1px solid var(--border);
  border-radius: 0;
  background: var(--card);
  color: var(--foreground);
  padding: 0.42rem 0.7rem;
  font-size: 0.78rem;
  font-weight: 700;
  cursor: pointer;
}

.onboarding-action-buttons button:disabled {
  cursor: not-allowed;
  color: var(--muted-foreground);
  border-color: var(--border);
}

.chat-main {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 0.75rem;
  min-height: 0;
}

.chat-main--with-seeds {
  grid-template-columns: minmax(0, 1fr) 280px;
}

/* Workspace sidebar — full-height left panel */
.workspace-sidebar {
  width: 200px;
  flex-shrink: 0;
  border-right: 1px solid var(--border);
  background: var(--card);
  display: flex;
  flex-direction: column;
  padding: 0.5rem 0;
  overflow-y: auto;
}

.sidebar-section {
  display: flex;
  flex-direction: column;
  padding: 0 0.5rem;
}

.sidebar-section--chats {
  flex: 1;
  min-height: 0;
  overflow-y: auto;
}

.sidebar-section-label {
  font-size: 0.68rem;
  font-weight: 700;
  color: var(--muted-foreground);
  text-transform: uppercase;
  letter-spacing: 0.04em;
  padding: 0.45rem 0.35rem 0.2rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.sidebar-new-chat-btn {
  border: none;
  background: transparent;
  color: var(--muted-foreground);
  font-size: 1rem;
  font-weight: 700;
  cursor: pointer;
  line-height: 1;
  padding: 0 0.2rem;
  border-radius: 0;
}

.sidebar-new-chat-btn:hover {
  background: var(--hover);
  color: var(--foreground);
}

.sidebar-divider {
  height: 1px;
  background: var(--border);
  margin: 0.35rem 0.5rem;
}

.sidebar-item {
  display: block;
  width: 100%;
  border: none;
  border-radius: 0;
  background: transparent;
  padding: 0.3rem 0.4rem;
  font-size: 0.78rem;
  color: var(--card-foreground);
  text-align: left;
  text-decoration: none;
  cursor: pointer;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.sidebar-item:hover {
  background: var(--hover);
}

.sidebar-item--active {
  background: var(--active);
  color: var(--foreground);
  font-weight: 600;
}

.sidebar-project-item {
  font-weight: 600;
}

.sidebar-agent-item {
  color: var(--muted-foreground);
  cursor: default;
}

.sidebar-nav-item {
  margin: 0 0.5rem;
  font-weight: 600;
}

.sidebar-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 0.05rem;
}

.sidebar-branch-list {
  padding-left: 0;
}

.sidebar-conversation-item--branch {
  font-size: 0.72rem;
  color: var(--muted-foreground);
}

.seed-panel {
  border: 1px solid var(--border);
  border-radius: 0;
  background: var(--card);
  padding: 0.75rem;
}

.seed-panel h3 {
  margin: 0;
  font-size: 0.92rem;
  color: var(--foreground);
}

.seed-panel p {
  margin: 0.35rem 0 0.7rem;
  font-size: 0.78rem;
  color: var(--muted-foreground);
}

.seed-panel ul {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 0.45rem;
  max-height: 56vh;
  overflow: auto;
}

.seed-panel li button {
  width: 100%;
  border: 1px solid var(--border);
  border-radius: 0;
  background: var(--muted);
  padding: 0.5rem 0.55rem;
  text-align: left;
  cursor: pointer;
  display: grid;
  gap: 0.18rem;
  color: var(--foreground);
}

.seed-kind {
  display: inline-flex;
  width: fit-content;
  border-radius: 0;
  background: var(--entity-project-muted);
  color: var(--entity-project-fg);
  font-size: 0.65rem;
  font-weight: 700;
  padding: 0.15rem 0.42rem;
  text-transform: uppercase;
}

.seed-text {
  font-size: 0.79rem;
  color: var(--foreground);
}

.seed-meta,
.seed-label {
  font-size: 0.7rem;
  color: var(--muted-foreground);
}

.source-match-tag {
  margin-top: 0.4rem;
  display: inline-flex;
  border-radius: 0;
  background: var(--entity-decision-muted);
  color: var(--entity-decision-fg);
  font-size: 0.67rem;
  font-weight: 700;
  padding: 0.2rem 0.5rem;
}

.workspace-setup {
  max-width: 560px;
  margin: 1.5rem auto;
  border: 1px solid var(--border);
  border-radius: 0;
  background: var(--card);
  padding: 1rem;
}

.workspace-setup h2 {
  margin-top: 0;
  margin-bottom: 0.3rem;
}

.workspace-setup p {
  margin-top: 0;
  font-size: 0.9rem;
  color: var(--muted-foreground);
}

.workspace-form {
  display: grid;
  gap: 0.7rem;
}

.workspace-form label {
  display: grid;
  gap: 0.22rem;
  font-size: 0.82rem;
  font-weight: 600;
  color: var(--foreground);
}

.workspace-form input {
  border: 1px solid var(--input);
  border-radius: 0;
  padding: 0.55rem 0.65rem;
  background: var(--background);
  color: var(--foreground);
}

.workspace-form button {
  width: fit-content;
  border: 0;
  border-radius: 0;
  background: var(--ring);
  color: var(--foreground);
  padding: 0.48rem 0.85rem;
  font-weight: 700;
  cursor: pointer;
}

.workspace-form button:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

/* Reachat's framer-motion message wrappers can remain in hidden state; force visible. */
.reachat-page [style*="translateY(20px)"] {
  opacity: 1 !important;
  transform: none !important;
}

.reachat-page button[title="Upload"] {
  width: 2rem;
  height: 2rem;
  padding: 0;
  border: 1px solid var(--border);
  border-radius: 0;
  background: var(--muted);
  color: var(--foreground);
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.reachat-page button[title="Upload"]:hover {
  background: var(--hover);
  color: var(--foreground);
}

.reachat-page button[title="Upload"] svg {
  width: 1rem;
  height: 1rem;
  display: block;
}

.error-message {
  margin-top: 0.75rem;
  color: var(--destructive);
  font-weight: 600;
}

.extraction-block {
  display: flex;
  flex-direction: column;
  gap: 0.45rem;
  margin-top: 0.55rem;
}

.extraction-row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.45rem;
}

.entity-badge,
.relationship-badge {
  display: inline-flex;
  align-items: center;
  border-radius: 0;
  font-size: 0.73rem;
  line-height: 1;
  padding: 0.34rem 0.62rem;
  border: 1px solid transparent;
}

.entity-badge {
  background: var(--entity-task-muted);
  color: var(--entity-task-fg);
  border-color: var(--entity-task);
}

.relationship-badge {
  background: var(--entity-project-muted);
  color: var(--entity-project-fg);
  border-color: var(--entity-project);
}

.extraction-summary {
  margin-top: 0.7rem;
  border: 1px solid var(--border);
  border-radius: 0;
  background: var(--muted);
  padding: 0.65rem;
}

.extraction-summary-title {
  margin: 0 0 0.45rem;
  font-size: 0.78rem;
  font-weight: 700;
  color: var(--foreground);
}

.extraction-summary-grid {
  display: grid;
  gap: 0.45rem;
}

.entity-card {
  border: 1px solid var(--border);
  border-radius: 0;
  background: var(--card);
  padding: 0.5rem 0.55rem;
}

.entity-card-header {
  display: flex;
  justify-content: space-between;
  gap: 0.45rem;
}

.entity-kind {
  font-size: 0.67rem;
  font-weight: 700;
  color: var(--ring);
  text-transform: uppercase;
}

.entity-link {
  color: var(--ring);
  text-decoration: none;
  cursor: pointer;
  border-bottom: 1px dotted var(--ring);
  transition: border-color 0.15s, color 0.15s;
}

.entity-link:hover {
  color: var(--text);
  border-bottom-style: solid;
}

.entity-link-kind {
  font-size: 0.6rem;
  font-weight: 700;
  text-transform: uppercase;
  opacity: 0.7;
  margin-right: 0.25rem;
}

.entity-status {
  font-size: 0.67rem;
  font-weight: 700;
  color: var(--entity-task);
  text-transform: uppercase;
}

.entity-name {
  margin: 0.2rem 0;
  font-size: 0.84rem;
  font-weight: 600;
  color: var(--foreground);
}

.entity-confidence {
  margin: 0;
  font-size: 0.72rem;
  color: var(--muted-foreground);
}

.extraction-summary-meta {
  margin: 0.5rem 0 0;
  font-size: 0.72rem;
  color: var(--muted-foreground);
}

/* --- Work item suggestions --- */

.work-item-suggestion-list {
  margin-top: 0.7rem;
  border: 1px solid var(--border);
  border-radius: 0;
  background: var(--muted);
  padding: 0.65rem;
}

.work-item-suggestion-list-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 0.45rem;
}

.work-item-suggestion {
  border: 1px solid var(--border);
  border-radius: 0;
  background: var(--card);
  padding: 0.5rem 0.55rem;
  transition: opacity 0.2s;
}

.work-item-suggestion--accepted {
  border-color: var(--entity-task);
  background: var(--entity-task-muted);
}

.work-item-suggestion-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 0.45rem;
}

.work-item-actions {
  display: flex;
  gap: 0.3rem;
}

.work-item-btn {
  border: none;
  border-radius: 0;
  padding: 0.2rem 0.5rem;
  font-size: 0.7rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s;
}

.work-item-btn:disabled {
  opacity: 0.5;
  cursor: default;
}

.work-item-btn--accept {
  background: var(--ring);
  color: var(--foreground);
}

.work-item-btn--accept:hover:not(:disabled) {
  opacity: 0.85;
}

.work-item-btn--dismiss {
  background: var(--muted);
  color: var(--muted-foreground);
}

.work-item-btn--dismiss:hover:not(:disabled) {
  background: var(--hover);
}

.work-item-rationale {
  margin: 0.15rem 0;
  font-size: 0.76rem;
  color: var(--muted-foreground);
}

.work-item-duplicate-hint {
  margin: 0.15rem 0 0;
  font-size: 0.7rem;
  color: var(--entity-decision);
  font-style: italic;
}

.work-item-project {
  margin: 0.15rem 0 0;
  font-size: 0.7rem;
  color: var(--muted-foreground);
}

.work-item-priority {
  font-size: 0.6rem;
  font-weight: 600;
  padding: 0.1rem 0.3rem;
  border-radius: 0;
  background: var(--entity-decision-muted);
  color: var(--entity-decision-fg);
  text-transform: uppercase;
}

.work-item-accepted-badge {
  font-size: 0.67rem;
  font-weight: 700;
  color: var(--entity-task);
  text-transform: uppercase;
}

@media (max-width: 700px) {
  .app-shell {
    flex-direction: column;
    height: auto;
    min-height: 100vh;
  }

  .workspace-sidebar {
    width: 100%;
    border-right: none;
    border-bottom: 1px solid var(--border);
    max-height: 35vh;
    overflow-y: auto;
  }

  .reachat-page {
    min-height: 78vh;
    padding: 0.35rem;
  }

  .chat-main--with-seeds {
    grid-template-columns: 1fr;
  }

  .seed-panel ul {
    max-height: 28vh;
  }

  .workspace-toolbar {
    flex-direction: column;
    align-items: flex-start;
  }
}

/* --- Graph view --- */

.graph-canvas {
  position: relative;
  width: 100%;
  height: 100%;
  min-height: 64vh;
  background-image: radial-gradient(circle, var(--border) 1px, transparent 1px);
  background-size: 20px 20px;
  border-radius: 0;
  overflow: hidden;
}

.graph-page {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  grid-template-rows: auto minmax(0, 1fr);
  gap: 0.5rem;
  min-height: 72vh;
  padding: 0.75rem;
}

.graph-page--with-panel {
  grid-template-columns: minmax(0, 1fr) 384px;
}

.graph-page--with-panel .graph-toolbar {
  grid-column: 1 / -1;
}

.graph-toolbar {
  display: flex;
  align-items: center;
  gap: 0.6rem;
  border: 1px solid var(--border);
  border-radius: 0;
  background: var(--muted);
  padding: 0.5rem 0.8rem;
  flex-wrap: wrap;
}

.graph-toolbar select,
.graph-toolbar button {
  border: 1px solid var(--border);
  border-radius: 0;
  background: var(--card);
  color: var(--foreground);
  padding: 0.35rem 0.55rem;
  font-size: 0.78rem;
  font-weight: 600;
  cursor: pointer;
}

.graph-toolbar select:focus,
.graph-toolbar button:focus {
  outline: 2px solid var(--ring, #0057cc);
  outline-offset: 1px;
}

.graph-toolbar label {
  display: flex;
  align-items: center;
  gap: 0.3rem;
  font-size: 0.78rem;
  font-weight: 600;
  color: var(--foreground);
}

.graph-toolbar input[type="range"] {
  width: 80px;
}

.graph-empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  color: var(--muted-foreground);
  font-size: 0.9rem;
  min-height: 40vh;
}

/* Entity detail panel */

.entity-detail-panel {
  border: 1px solid var(--border);
  border-radius: 0;
  background: var(--card);
  padding: 0.75rem;
  overflow-y: auto;
  max-height: 80vh;
  display: flex;
  flex-direction: column;
  gap: 0.6rem;
  animation: slide-in-right 0.2s ease-out;
}

@keyframes slide-in-right {
  from {
    opacity: 0;
    transform: translateX(12px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

.entity-detail-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 0.5rem;
}

.entity-detail-header h3 {
  margin: 0;
  font-size: 0.95rem;
  color: var(--foreground);
}

.entity-detail-close {
  border: none;
  background: transparent;
  color: var(--muted-foreground);
  font-size: 1.1rem;
  cursor: pointer;
  padding: 0.1rem 0.3rem;
  line-height: 1;
}

.entity-detail-section {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

.entity-detail-section h4 {
  margin: 0;
  font-size: 0.72rem;
  font-weight: 700;
  color: var(--foreground);
  text-transform: uppercase;
  letter-spacing: 0.03em;
}

.entity-detail-meta {
  font-size: 0.78rem;
  color: var(--muted-foreground);
}

.entity-detail-meta dt {
  font-weight: 600;
  color: var(--foreground);
  display: inline;
}

.entity-detail-meta dt::after {
  content: ": ";
}

.entity-detail-meta dd {
  display: inline;
  margin: 0;
}

.entity-detail-meta dd::after {
  content: "";
  display: block;
  margin-bottom: 0.15rem;
}

.entity-detail-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem;
  padding-top: 0.3rem;
}

.entity-detail-actions button {
  border: 1px solid var(--border);
  border-radius: 0;
  background: var(--card);
  color: var(--foreground);
  padding: 0.35rem 0.6rem;
  font-size: 0.78rem;
  font-weight: 600;
  cursor: pointer;
}

.entity-detail-actions button:hover {
  background: var(--hover);
}

.entity-detail-actions button:disabled {
  cursor: not-allowed;
  color: var(--muted-foreground);
  border-color: var(--border);
}

/* Description section */

.entity-detail-description {
  font-size: 0.82rem;
  color: var(--card-foreground);
  line-height: 1.5;
  margin: 0;
}

.description-timeline-toggle {
  border: none;
  background: transparent;
  font-size: 0.7rem;
  color: var(--muted-foreground);
  cursor: pointer;
  padding: 0.2rem 0;
  text-align: left;
}

.description-timeline-toggle:hover {
  color: var(--foreground);
}

.description-timeline {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  border-left: 2px solid var(--border);
  padding-left: 0.75rem;
  margin-top: 0.25rem;
}

.description-timeline-entry {
  display: flex;
  flex-direction: column;
  gap: 0.1rem;
}

.description-timeline-date {
  font-size: 0.65rem;
  color: var(--muted-foreground);
  font-weight: 600;
}

.description-timeline-text {
  font-size: 0.76rem;
  color: var(--card-foreground);
}

.description-timeline-reasoning {
  font-size: 0.65rem;
  color: var(--muted-foreground);
  font-style: italic;
}

.description-timeline-triggers {
  display: flex;
  flex-wrap: wrap;
  gap: 0.25rem;
}

.description-timeline-trigger {
  border: none;
  background: transparent;
  font-size: 0.65rem;
  color: var(--ring);
  cursor: pointer;
  padding: 0;
  text-align: left;
}

.description-timeline-trigger:hover {
  color: var(--foreground);
  text-decoration: underline;
}

/* Entity badge (inline kind indicator) */

.entity-badge-inline {
  display: inline-flex;
  align-items: center;
  gap: 0.25rem;
  border-radius: 0;
  font-size: 0.67rem;
  font-weight: 700;
  padding: 0.15rem 0.42rem;
  text-transform: uppercase;
}

.category-badge {
  display: inline-flex;
  align-items: center;
  gap: 0.25rem;
  border-radius: 0;
  font-size: 0.6rem;
  font-weight: 600;
  padding: 0.12rem 0.38rem;
  background: var(--muted);
  color: var(--muted-foreground);
  text-transform: capitalize;
}

/* Relationship list in detail panel */

.relationship-group {
  display: flex;
  flex-direction: column;
  gap: 0.15rem;
}

.relationship-group-label {
  font-size: 0.67rem;
  font-weight: 700;
  color: var(--muted-foreground);
  text-transform: uppercase;
  letter-spacing: 0.03em;
}

.relationship-item {
  display: flex;
  align-items: center;
  gap: 0.35rem;
  padding: 0.25rem 0.35rem;
  border-radius: 0;
  cursor: pointer;
  font-size: 0.78rem;
  color: var(--card-foreground);
}

.relationship-item:hover {
  background: var(--hover);
}

/* Provenance section */

.provenance-item {
  border: 1px solid var(--border);
  border-radius: 0;
  padding: 0.4rem 0.5rem;
  font-size: 0.76rem;
  color: var(--card-foreground);
  display: flex;
  flex-direction: column;
  gap: 0.15rem;
}

.provenance-evidence {
  font-style: italic;
  color: var(--muted-foreground);
}

.provenance-link {
  color: var(--ring);
  text-decoration: none;
  font-weight: 600;
  font-size: 0.72rem;
  cursor: pointer;
}

.provenance-link:hover {
  text-decoration: underline;
}

/* View tabs */

/* Graph icon on entity card */

.entity-card-graph-link {
  border: none;
  background: transparent;
  color: var(--ring);
  cursor: pointer;
  padding: 0.15rem;
  line-height: 1;
  font-size: 0.8rem;
  border-radius: 0;
}

.entity-card-graph-link:hover {
  background: var(--hover);
}

/* Message highlight animation (graph → chat navigation) */

@keyframes highlight-message {
  0% {
    background: rgba(0, 87, 204, 0.15);
  }
  100% {
    background: transparent;
  }
}

.animate-highlight {
  animation: highlight-message 2s ease-out;
}

/* Branch: inherited messages */
.message-inherited {
  opacity: 0.55;
  border-left: 2px solid var(--border, #d0d0d0);
  padding-left: 8px;
}

.branch-divider {
  text-align: center;
  font-size: 0.75rem;
  color: var(--muted-foreground, #888);
  padding: 8px 0;
  border-bottom: 1px dashed var(--border, #d0d0d0);
  margin-bottom: 8px;
}

.branch-message-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  margin: 2px 0 8px auto;
  padding: 4px;
  color: var(--muted-foreground, #888);
  background: transparent;
  border: 1px solid transparent;
  border-radius: 0;
  cursor: pointer;
  opacity: 0;
  transition: opacity 0.15s, background 0.15s, border-color 0.15s;
}

[data-message-id]:hover .branch-message-btn {
  opacity: 0.5;
}

.branch-message-btn:hover {
  opacity: 1 !important;
