 65→
 66→          if (state.finished) {
 67→            controller.close();
 68→            cleanupStream(messageId, "finished_before_start");
 69→            return;
 70→          }
 71→
 72→          state.keepAliveId = setInterval(() => {
 73→            controller.enqueue(encoder.encode(": keep-alive\n\n"));
 74→          }, 15_000);
 75→        },
 76→        cancel() {
 77→          cleanupStream(messageId, "client_cancelled");
 78→        },
 79→      });
 80→
 81→      return new Response(stream, {
 82→        headers: {
