 46→export async function buildChatContext(input: {
 47→  surreal: Surreal;
 48→  conversationRecord: RecordId<"conversation", string>;
 49→  workspaceRecord: RecordId<"workspace", string>;
 50→  loaders?: ChatContextLoaders;
 51→  inheritedEntityIds?: RecordId[];
 52→  discussesRecord?: RecordId;
 53→}): Promise<ChatContext> {
 54→  const loaders = input.loaders ?? {
 55→    listConversationEntities,
 56→    listWorkspaceProjectSummaries,
 57→    listWorkspaceRecentDecisions,
 58→    listWorkspaceOpenQuestions,
 59→    listWorkspaceOpenObservations,
 60→    loadOnboardingSummary,
 61→  };
 62→
 63→  const [conversationEntities, projects, recentDecisions, openQuestions, openObservations, onboardingSummary] = await Promise.all([
 64→    loaders.listConversationEntities({
 65→      surreal: input.surreal,
 66→      conversationRecord: input.conversationRecord,
 67→      workspaceRecord: input.workspaceRecord,
 68→      limit: 60,
 69→      ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 70→        ? { inheritedEntityIds: input.inheritedEntityIds }
 71→        : {}),
 72→    }),
 73→    loaders.listWorkspaceProjectSummaries({
 74→      surreal: input.surreal,
 75→      workspaceRecord: input.workspaceRecord,
 76→      limit: 20,
 77→    }),
 78→    loaders.listWorkspaceRecentDecisions({
 79→      surreal: input.surreal,
 80→      workspaceRecord: input.workspaceRecord,
 81→      limit: 12,
 82→    }),
 83→    loaders.listWorkspaceOpenQuestions({
 84→      surreal: input.surreal,
 85→      workspaceRecord: input.workspaceRecord,
 86→      limit: 12,
 87→    }),
 88→    loaders.listWorkspaceOpenObservations({
 89→      surreal: input.surreal,
 90→      workspaceRecord: input.workspaceRecord,
 91→      limit: 10,
 92→    }),
 93→    loaders.loadOnboardingSummary(input.surreal, input.workspaceRecord),
 94→  ]);
 95→
 96→  let discussedEntity: DiscussedEntityContext | undefined;
 97→  if (input.discussesRecord) {
 98→    const entityRecord = input.discussesRecord as GraphEntityRecord;
 99→    const name = await readEntityName(input.surreal, entityRecord);
100→    if (name) {
101→      const row = await input.surreal.select<Record<string, unknown>>(entityRecord);
102→      discussedEntity = {
103→        kind: entityRecord.table.name,
104→        name,
105→        ...(row && typeof row.status === "string" ? { status: row.status } : {}),
106→      };
107→    }
108→  }
109→
110→  return {
111→    conversationEntities,
112→    workspaceSummary: {
113→      projects,
114→      recentDecisions,
115→      openQuestions,
