  1→import { stepCountIs, streamText, type ModelMessage } from "ai";
  2→import { RecordId, Surreal } from "surrealdb";
  3→import type { ExtractedEntity, ExtractedRelationship, OnboardingState } from "../../shared/contracts";
  4→import { logInfo, logError } from "../http/observability";
  5→import { buildChatContext, buildSystemPrompt, type ChatContext } from "./context";
  6→import { createChatAgentTools } from "./tools";
  7→
  8→type ConversationMessage = {
  9→  role: "user" | "assistant";
 10→  text: string;
 11→};
 12→
 13→type CollectedEntity = ExtractedEntity;
 14→type CollectedRelationship = ExtractedRelationship;
 15→
 16→export type ChatAgentResult = {
 17→  text: string;
 18→  collectedEntities: CollectedEntity[];
 19→  collectedRelationships: CollectedRelationship[];
 20→};
 21→
 22→export async function runChatAgent(input: {
 23→  surreal: Surreal;
 24→  model: any;
 25→  pmAgentModel: any;
 26→  analyticsAgentModel: any;
 27→  analyticsSurreal: Surreal;
 28→  embeddingModel: any;
 29→  embeddingDimension: number;
 30→  extractionModelId: string;
 31→  extractionModel: any;
 32→  extractionStoreThreshold: number;
 33→  conversationRecord: RecordId<"conversation", string>;
 34→  workspaceRecord: RecordId<"workspace", string>;
 35→  currentMessageRecord: RecordId<"message", string>;
 36→  latestUserText: string;
 37→  workspaceOwnerRecord?: RecordId<"person", string>;
 38→  inheritedEntityIds?: RecordId[];
 39→  discussesRecord?: RecordId;
 40→  messages: ConversationMessage[];
 41→  isOnboarding?: boolean;
 42→  onboardingState?: OnboardingState;
 43→  onToken: (token: string) => Promise<void> | void;
 44→}): Promise<ChatAgentResult> {
 45→  const context = await buildChatContext({
 46→    surreal: input.surreal,
 47→    conversationRecord: input.conversationRecord,
 48→    workspaceRecord: input.workspaceRecord,
 49→    ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 50→      ? { inheritedEntityIds: input.inheritedEntityIds }
 51→      : {}),
 52→    ...(input.discussesRecord ? { discussesRecord: input.discussesRecord } : {}),
 53→  });
 54→
 55→  const system = buildSystemPrompt(context, {
 56→    isOnboarding: input.isOnboarding,
 57→    onboardingState: input.onboardingState,
 58→  });
 59→
 60→  const modelMessages: ModelMessage[] = input.messages.map((message) => ({
 61→    role: message.role,
 62→    content: message.text,
 63→  }));
 64→
 65→  const result = streamText({
 66→    model: input.model,
 67→    system,
 68→    messages: modelMessages,
 69→    tools: createChatAgentTools({
 70→      surreal: input.surreal,
 71→      pmAgentModel: input.pmAgentModel,
 72→      analyticsAgentModel: input.analyticsAgentModel,
 73→      analyticsSurreal: input.analyticsSurreal,
 74→      embeddingModel: input.embeddingModel,
 75→      embeddingDimension: input.embeddingDimension,
 76→      extractionModelId: input.extractionModelId,
 77→      extractionModel: input.extractionModel,
 78→      extractionStoreThreshold: input.extractionStoreThreshold,
 79→    }),
 80→    experimental_context: {
 81→      actor: "chat_agent",
 82→      workspaceRecord: input.workspaceRecord,
 83→      conversationRecord: input.conversationRecord,
 84→      currentMessageRecord: input.currentMessageRecord,
 85→      latestUserText: input.latestUserText,
 86→      ...(input.workspaceOwnerRecord ? { workspaceOwnerRecord: input.workspaceOwnerRecord } : {}),
 87→    },
 88→    stopWhen: stepCountIs(5),
 89→  });
 90→
 91→  let text = "";
 92→  const collectedEntities: CollectedEntity[] = [];
 93→  const collectedRelationships: CollectedRelationship[] = [];
 94→
 95→  for await (const part of result.fullStream) {
 96→    if (part.type === "text-delta") {
 97→      text = `${text}${part.text}`;
 98→      await input.onToken(part.text);
 99→      continue;
100→    }
101→
102→    if (part.type === "tool-call") {
103→      logInfo("chat.agent.tool_call", "Chat agent invoked tool", part);
104→    }
105→
106→    if (part.type === "tool-result") {
107→      logInfo("chat.agent.tool_result", "Chat agent tool returned", part);
108→      const toolResult = part.output as Record<string, unknown> | undefined;
109→      if (toolResult) {
110→        if (Array.isArray(toolResult.extracted_entities)) {
111→          collectedEntities.push(...(toolResult.extracted_entities as CollectedEntity[]));
112→        }
113→        if (Array.isArray(toolResult.extracted_relationships)) {
114→          collectedRelationships.push(...(toolResult.extracted_relationships as CollectedRelationship[]));
115→        }
116→      }
117→    }
118→
119→    if (part.type === "error") {
120→      logError("chat.agent.stream_error", "Chat agent stream error", part.error, {});
121→    }
122→  }
123→
124→  if (text.trim().length === 0) {
125→    text = await result.text;
126→  }
127→
128→  // Post-process: inject entity:// links for entity names mentioned in the response.
129→  const linked = injectEntityLinks(text, context);
130→  if (linked !== text) {
131→    // Re-send the full linked text as a replacement.
132→    // The SSE stream already sent raw text; the persisted version will have links.
133→    text = linked;
134→  }
135→
136→  return {
137→    text: text.trim(),
138→    collectedEntities,
139→    collectedRelationships,
140→  };
141→}
