  1→import { RecordId } from "surrealdb";
  2→import type { ExtractedEntity, ExtractedRelationship, OnboardingAction } from "../../shared/contracts";
  3→import { loadAssistantConversationContext } from "../extraction/context-loaders";
  4→import { loadBranchChain, loadMessagesWithInheritance } from "./branch-chain";
  5→import { ingestAttachment } from "../extraction/document-ingestion";
  6→import { createEmbedding, persistEmbeddings } from "../extraction/embedding-writeback";
  7→import { appendExtractedTools } from "../extraction/persist-extraction";
  8→import type { ConversationRow, GraphEntityRecord, IncomingAttachment, WorkspaceRow } from "../extraction/types";
  9→import { elapsedMs, logError, logInfo, userFacingError } from "../http/observability";
 10→import { transitionOnboardingState } from "../onboarding/onboarding-state";
 11→import type { ServerDependencies } from "../runtime/types";
 12→import { runChatAgent } from "./handler";
 13→import { getWorkspaceOwnerRecord } from "../graph/queries";
 14→import { refreshConversationTouchedBy, maybeUpgradeConversationTitle } from "../workspace/conversation-sidebar";
 15→import { loadWorkspaceProjects } from "../workspace/workspace-scope";
 16→
 17→export async function processChatMessage(input: {
 18→  deps: ServerDependencies;
 19→  conversationId: string;
 20→  messageId: string;
 21→  workspaceRecord: RecordId<"workspace", string>;
 22→  userMessageRecord: RecordId<"message", string>;
 23→  userText: string;
 24→  attachment?: IncomingAttachment;
 25→  onboardingAction?: OnboardingAction;
 26→}): Promise<void> {
 27→  const startedAt = performance.now();
 28→  logInfo("chat.message.process.execution.started", "Chat message processing execution started", {
 29→    conversationId: input.conversationId,
 30→    messageId: input.messageId,
 31→    workspaceId: input.workspaceRecord.id as string,
 32→    hasAttachment: input.attachment !== undefined,
 33→  });
 34→
 35→  try {
 36→    const now = new Date();
 37→    const conversationRecord = new RecordId("conversation", input.conversationId);
 38→    const workspace = await input.deps.surreal.select<WorkspaceRow>(input.workspaceRecord);
 39→    if (!workspace) {
 40→      throw new Error("workspace not found");
 41→    }
 42→
 43→    const conversation = await input.deps.surreal.select<ConversationRow>(conversationRecord);
 44→    if (!conversation) {
 45→      throw new Error("conversation not found");
 46→    }
 47→
 48→    // Check if this conversation is a branch and load inherited context
 49→    const branchChain = await loadBranchChain(input.deps.surreal, input.conversationId);
 50→    const isBranch = branchChain.length > 0;
 51→
 52→    let inheritedEntityIds: RecordId[] | undefined;
 53→    let assistantContextRows: Array<{ id: RecordId<"message", string>; role: "user" | "assistant"; text: string; createdAt: Date | string }>;
 54→
 55→    if (isBranch) {
 56→      // For branches, load full message history including inherited messages
 57→      const allMessages = await loadMessagesWithInheritance(input.deps.surreal, input.conversationId, 30);
 58→      assistantContextRows = allMessages
 59→        .map((m) => ({
 60→          id: new RecordId("message", m.id),
 61→          role: m.role,
 62→          text: m.text,
 63→          createdAt: m.createdAt,
 64→        }))
 65→        .slice(-10);
 66→
 67→      // Derive inherited entity IDs from extraction_relations on inherited messages
 68→      const inheritedMsgIds = allMessages
 69→        .filter((m) => m.inherited)
 70→        .map((m) => new RecordId("message", m.id));
 71→
 72→      if (inheritedMsgIds.length > 0) {
 73→        const [entityRows] = await input.deps.surreal
 74→          .query<[Array<{ out: RecordId }>]>(
 75→            "SELECT DISTINCT out FROM extraction_relation WHERE `in` IN $msgIds LIMIT 30;",
 76→            { msgIds: inheritedMsgIds },
 77→          )
 78→          .collect<[Array<{ out: RecordId }>]>();
 79→        inheritedEntityIds = entityRows.map((r) => r.out);
 80→      }
 81→    } else {
 82→      assistantContextRows = await loadAssistantConversationContext(input.deps.surreal, input.conversationId);
 83→    }
 84→
 85→    // Embed user message early: used for context enrichment and persisted to the message record
 86→    const userMessageEmbedding = await createEmbedding(input.deps.embeddingModel, input.deps.config.embeddingDimension, input.userText);
 87→    if (userMessageEmbedding) {
 88→      void input.deps.surreal
 89→        .query("UPDATE $record MERGE { embedding: $embedding };", {
 90→          record: input.userMessageRecord,
 91→          embedding: userMessageEmbedding,
 92→        })
 93→        .catch(() => undefined);
 94→    }
 95→
 96→    const workspaceProjects = await loadWorkspaceProjects(input.deps.surreal, input.workspaceRecord);
 97→    const workspaceProjectNames = workspaceProjects.map((project) => project.name);
 98→    const persistedEntities: ExtractedEntity[] = [];
 99→    const persistedRelationships: ExtractedRelationship[] = [];
100→    const embeddingTargets: Array<{ record: GraphEntityRecord; text: string }> = [];
101→    const extractedTools: string[] = [];
102→    const unresolvedAssigneeNames = new Set<string>();
103→
104→    // Attachment extraction stays automatic — document ingestion is intentional
105→    if (input.attachment) {
106→      const ingestion = await ingestAttachment({
107→        surreal: input.deps.surreal,
108→        extractionModel: input.deps.extractionModel,
109→        embeddingModel: input.deps.embeddingModel,
110→        embeddingDimension: input.deps.config.embeddingDimension,
111→        extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
112→        extractionModelId: input.deps.config.extractionModelId,
113→        workspaceRecord: input.workspaceRecord,
114→        conversationRecord,
115→        userMessageRecord: input.userMessageRecord,
116→        attachment: input.attachment,
117→        workspaceName: workspace.name,
118→        projectNames: workspaceProjectNames,
119→        now,
120→        onChunkResult: (chunkResult) => {
121→          if (chunkResult.entities.length > 0 || chunkResult.relationships.length > 0) {
122→            input.deps.sse.emitEvent(input.messageId, {
123→              type: "extraction",
124→              messageId: input.messageId,
125→              entities: chunkResult.entities,
126→              relationships: chunkResult.relationships,
127→            });
128→          }
129→        },
130→      });
131→
132→      persistedEntities.push(...ingestion.entities);
133→      persistedRelationships.push(...ingestion.relationships);
134→      embeddingTargets.push(...ingestion.embeddingTargets);
135→      extractedTools.push(...ingestion.tools);
136→      for (const unresolvedName of ingestion.unresolvedAssigneeNames) {
137→        unresolvedAssigneeNames.add(unresolvedName);
138→      }
139→    }
140→
141→    if (extractedTools.length > 0) {
142→      await appendExtractedTools(input.deps.surreal, input.workspaceRecord, extractedTools, now);
143→    }
144→
145→    const onboardingBefore = workspace.onboarding_complete
146→      ? "complete"
147→      : workspace.onboarding_summary_pending
148→        ? "summary_pending"
149→        : "active";
150→
151→    const onboardingAfter = await transitionOnboardingState({
152→      surreal: input.deps.surreal,
153→      workspaceRecord: input.workspaceRecord,
154→      workspace,
155→      onboardingAction: input.onboardingAction,
156→      now,
157→    });
158→
159→    // Always run chat agent — it handles both onboarding and post-onboarding
160→    const workspaceOwnerRecord = await getWorkspaceOwnerRecord({
161→      surreal: input.deps.surreal,
162→      workspaceRecord: input.workspaceRecord,
163→    });
164→
165→    const graphAwareResponse = await runChatAgent({
166→      surreal: input.deps.surreal,
167→      model: input.deps.chatAgentModel,
168→      pmAgentModel: input.deps.pmAgentModel,
169→      analyticsAgentModel: input.deps.analyticsAgentModel,
170→      analyticsSurreal: input.deps.analyticsSurreal,
171→      embeddingModel: input.deps.embeddingModel,
172→      embeddingDimension: input.deps.config.embeddingDimension,
173→      extractionModelId: input.deps.config.extractionModelId,
174→      extractionModel: input.deps.extractionModel,
175→      extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
176→      conversationRecord,
177→      workspaceRecord: input.workspaceRecord,
178→      currentMessageRecord: input.userMessageRecord,
179→      latestUserText: input.userText,
180→      isOnboarding: onboardingAfter !== "complete",
181→      onboardingState: onboardingAfter,
182→      ...(workspaceOwnerRecord ? { workspaceOwnerRecord } : {}),
183→      ...(userMessageEmbedding ? { userMessageEmbedding } : {}),
184→      ...(inheritedEntityIds && inheritedEntityIds.length > 0 ? { inheritedEntityIds } : {}),
185→      ...(conversation.discusses ? { discussesRecord: conversation.discusses } : {}),
186→      messages: assistantContextRows.map((row) => ({
187→        role: row.role,
188→        text: row.text,
189→      })),
190→      onToken: async (token) => {
191→        input.deps.sse.emitEvent(input.messageId, {
192→          type: "token",
193→          messageId: input.messageId,
194→          token,
195→        });
196→      },
197→      onReasoning: async (token) => {
198→        input.deps.sse.emitEvent(input.messageId, {
199→          type: "reasoning",
200→          messageId: input.messageId,
201→          token,
202→        });
203→      },
204→    });
205→
206→    let assistantText = graphAwareResponse.text.trim();
207→    persistedEntities.push(...graphAwareResponse.collectedEntities);
208→    persistedRelationships.push(...graphAwareResponse.collectedRelationships);
209→
210→    const unresolvedAssigneeSuggestions = [...unresolvedAssigneeNames].map(
211→      (name) => `You mentioned ${name} - want to add them to workspace people?`,
212→    );
213→    const assistantSuggestions = sanitizeAssistantSuggestions(unresolvedAssigneeSuggestions, 3);
214→
215→    // Post-response hooks (entities now created during chat agent execution)
216→    await refreshConversationTouchedBy(input.deps.surreal, conversationRecord);
217→    await maybeUpgradeConversationTitle(input.deps.surreal, conversationRecord);
218→
219→    if (assistantText.trim().length === 0) {
220→      assistantText = "I could not generate a response for that request.";
221→    }
222→
223→    const assistantMessageRecord = new RecordId("message", input.messageId);
224→    await input.deps.surreal.create(assistantMessageRecord).content({
225→      conversation: conversationRecord,
226→      role: "assistant",
227→      text: assistantText,
228→      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
229→      createdAt: now,
230→    });
231→
232→    await input.deps.surreal.update(conversationRecord).merge({
233→      updatedAt: now,
234→    });
235→
236→    void persistEmbeddings({
237→      surreal: input.deps.surreal,
238→      embeddingModel: input.deps.embeddingModel,
239→      embeddingDimension: input.deps.config.embeddingDimension,
240→      assistantMessageRecord,
241→      assistantText,
242→      entities: embeddingTargets,
243→    }).catch(() => undefined);
244→
245→    input.deps.sse.emitEvent(input.messageId, {
246→      type: "extraction",
247→      messageId: input.messageId,
248→      entities: persistedEntities,
249→      relationships: persistedRelationships,
250→    });
251→
252→    if (onboardingBefore !== onboardingAfter) {
253→      input.deps.sse.emitEvent(input.messageId, {
254→        type: "onboarding_state",
255→        messageId: input.messageId,
256→        onboardingState: onboardingAfter,
257→      });
258→    }
259→
260→    input.deps.sse.emitEvent(input.messageId, {
261→      type: "assistant_message",
262→      messageId: input.messageId,
263→      text: assistantText,
264→      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
265→    });
266→
267→    input.deps.sse.emitEvent(input.messageId, {
268→      type: "done",
269→      messageId: input.messageId,
270→    });
271→
272→    logInfo("chat.message.process.execution.completed", "Chat message processing execution completed", {
273→      conversationId: input.conversationId,
274→      messageId: input.messageId,
275→      workspaceId: input.workspaceRecord.id as string,
276→      entityCount: persistedEntities.length,
277→      relationshipCount: persistedRelationships.length,
278→      durationMs: elapsedMs(startedAt),
279→    });
280→  } catch (error) {
281→    logError("chat.message.process.execution.failed", "Chat message processing execution failed", error, {
282→      conversationId: input.conversationId,
283→      messageId: input.messageId,
284→      workspaceId: input.workspaceRecord.id as string,
285→      durationMs: elapsedMs(startedAt),
286→    });
287→    const errorText = userFacingError(error, "chat processing failed");
288→    input.deps.sse.emitEvent(input.messageId, {
289→      type: "error",
290→      messageId: input.messageId,
291→      error: errorText,
292→    });
293→  }
294→}
295→
296→function sanitizeAssistantSuggestions(suggestions: string[], limit: number): string[] {
297→  return [...new Set(suggestions.map((value) => value.trim()))]
298→    .filter((value) => value.length > 0 && value.length <= 140)
299→    .slice(0, limit);
300→}
301→

