  1→import { MouseEvent, useEffect, useMemo, useRef, useState } from "react";
  2→import type {
  3→  Session,
  4→  Suggestion,
  5→  MentionItem,
  6→  ChatInputRef,
  7→} from "reachat";
  8→import type {
  9→  BranchConversationResponse,
 10→  ChatMessageResponse,
 11→  DiscussEntitySummary,
 12→  OnboardingAction,
 13→  SearchEntityResponse,
 14→  StreamEvent as ChatStreamEvent,
 15→  WorkspaceConversationResponse,
 16→} from "../../shared/contracts";
 17→import { useWorkspaceState, type BootstrapPayload } from "../stores/workspace-state";
 18→import { useViewState } from "../stores/view-state";
 19→
 20→type UseChatSessionReturn = {
 21→  sessions: Session[];
 22→  activeSessionId: string;
 23→  activeSession: Session;
 24→  activeConversationId?: string;
 25→  isLoading: boolean;
 26→  errorMessage?: string;
 27→  suggestions: Suggestion[];
 28→  pendingFile?: File;
 29→  branchingFromId?: string;
 30→  inheritedMessageIds: Set<string>;
 31→  discussEntity?: DiscussEntitySummary;
 32→  conversationDiscussEntity?: DiscussEntitySummary;
 33→  chatInputRef: React.RefObject<ChatInputRef | null>;
 34→  onSendMessage: (message: string, options?: { onboardingAction?: OnboardingAction }) => Promise<void>;
 35→  onStopMessage: () => void;
 36→  onNewConversation: () => void;
 37→  onSelectConversation: (conversationId: string) => void;
 38→  onBranchFromMessage: (messageId: string) => Promise<void>;
 39→  searchMentions: (query: string) => Promise<MentionItem[]>;
 40→  onUploadFile: (file: File) => void;
 41→  onChatInputClickCapture: (event: MouseEvent<HTMLDivElement>) => void;
 42→  reasoningByMessageId: Map<string, string>;
 43→  setErrorMessage: (message: string | undefined) => void;
 44→  refreshSidebar: (workspaceId: string) => Promise<void>;
 45→};
 46→
 47→export function useChatSession(): UseChatSessionReturn {
 48→  const store = useWorkspaceState();
 49→  const workspaceId = store.workspaceId;
 50→  const workspaceName = store.workspaceName;
 51→  const bootstrapPayload = store.bootstrapPayload;
 52→
 53→  const [sessions, setSessions] = useState<Session[]>([
 54→    {
 55→      id: "main",
 56→      title: "Workspace Chat",
 57→      createdAt: new Date(),
 58→      updatedAt: new Date(),
 59→      conversations: [],
 60→    },
 61→  ]);
 62→  const [activeSessionId] = useState("main");
 63→  const [backendConversationId, setBackendConversationId] = useState<string | undefined>();
 64→  const [activeConversationId, setActiveConversationId] = useState<string | undefined>();
 65→  const [isLoading, setIsLoading] = useState(false);
 66→  const [errorMessage, setErrorMessage] = useState<string | undefined>();
 67→  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
 68→  const [branchingFromId, setBranchingFromId] = useState<string | undefined>();
 69→  const [inheritedMessageIds, setInheritedMessageIds] = useState<Set<string>>(new Set());
 70→  const [pendingFile, setPendingFile] = useState<File | undefined>();
 71→  const [conversationDiscussEntity, setConversationDiscussEntity] = useState<DiscussEntitySummary | undefined>();
 72→  const [reasoningByMessageId, setReasoningByMessageId] = useState<Map<string, string>>(new Map());
 73→  const streamRef = useRef<EventSource | undefined>(undefined);
 74→  const chatInputRef = useRef<ChatInputRef | null>(null);
 75→
 76→  const discussEntity = useViewState((s) => s.discussEntity);
 77→  const clearDiscussEntity = useViewState((s) => s.clearDiscussEntity);
 78→
 79→  // Track the last applied bootstrap payload to avoid re-applying
 80→  const appliedBootstrapRef = useRef<BootstrapPayload | undefined>(undefined);
 81→
 82→  const activeSession = useMemo(
 83→    () => sessions.find((session) => session.id === activeSessionId),
 84→    [sessions, activeSessionId],
 85→  );
 86→
 87→  if (!activeSession) {
 88→    throw new Error("active session missing");
 89→  }
 90→
 91→  // Apply bootstrap payload when it arrives
 92→  useEffect(() => {
 93→    if (!bootstrapPayload || bootstrapPayload === appliedBootstrapRef.current) {
 94→      return;
 95→    }
 96→    appliedBootstrapRef.current = bootstrapPayload;
 97→
 98→    setSessions([
 99→      {
100→        id: "main",
101→        title: workspaceName ?? "Workspace Chat",
102→        createdAt: new Date(),
103→        updatedAt: new Date(),
104→        conversations: bootstrapPayload.conversations,
105→      },
106→    ]);
107→    setInheritedMessageIds(bootstrapPayload.inheritedIds);
108→    setSuggestions(
109→      bootstrapPayload.latestSuggestions.map((content, index) => ({
110→        id: `bootstrap-suggestion-${index}-${content}`,
111→        content,
112→      })),
113→    );
114→    setActiveConversationId(store.conversationId);
115→    setBackendConversationId(store.conversationId);
116→  }, [bootstrapPayload]);
117→
118→  // Highlight message support (graph -> chat navigation)
119→  const highlightMessageId = useViewState((s) => s.highlightMessageId);
120→  const clearHighlight = useViewState((s) => s.clearHighlight);
121→
122→  useEffect(() => {
123→    if (!highlightMessageId) return;
124→
125→    const timer = setTimeout(() => {
126→      const element = document.querySelector(`[data-message-id="${highlightMessageId}"]`);
127→      if (element) {
128→        element.scrollIntoView({ behavior: "smooth", block: "center" });
129→        element.classList.add("animate-highlight");
130→        element.addEventListener(
131→          "animationend",
132→          () => {
133→            element.classList.remove("animate-highlight");
134→          },
135→          { once: true },
136→        );
137→      }
138→      clearHighlight();
139→    }, 100);
140→
141→    return () => clearTimeout(timer);
142→  }, [highlightMessageId, clearHighlight]);
143→
144→  async function refreshSidebar(wsId: string) {
145→    try {
146→      const response = await fetch(`/api/workspaces/${encodeURIComponent(wsId)}/sidebar`);
147→      if (response.ok) {
148→        const payload = await response.json();
149→        store.setSidebar(payload);
150→      }
151→    } catch {
152→      // Sidebar refresh is non-critical; silently ignore
153→    }
154→  }
155→
156→  async function loadConversation(wsId: string, conversationId: string) {
157→    try {
158→      const response = await fetch(
159→        `/api/workspaces/${encodeURIComponent(wsId)}/conversations/${encodeURIComponent(conversationId)}`,
160→      );
161→      if (!response.ok) {
162→        const body = await response.text();
163→        setErrorMessage(body);
164→        return;
165→      }
166→
167→      const payload = (await response.json()) as WorkspaceConversationResponse;
168→      const conversations: Session["conversations"] = [];
169→      let latestSuggestions: string[] = [];
170→      const inheritedIds = new Set<string>();
171→
172→      for (const message of payload.messages) {
173→        if (message.role === "user") {
174→          conversations.push({
175→            id: message.id,
176→            question: message.text,
177→            createdAt: new Date(message.createdAt),
178→          });
179→          if (message.inherited) {
180→            inheritedIds.add(message.id);
181→          }
182→          continue;
183→        }
184→
185→        const last = conversations[conversations.length - 1];
186→        if (last && !last.response) {
187→          last.response = message.text;
188→          last.updatedAt = new Date(message.createdAt);
189→          latestSuggestions =
190→            message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
191→          if (message.inherited) {
192→            inheritedIds.add(last.id);
193→          }
194→          continue;
195→        }
196→
197→        conversations.push({
198→          id: `assistant-${message.id}`,
199→          question: "",
200→          response: message.text,
201→          createdAt: new Date(message.createdAt),
202→        });
203→        if (message.inherited) {
204→          inheritedIds.add(`assistant-${message.id}`);
205→        }
206→        latestSuggestions =
207→          message.suggestions && message.suggestions.length > 0 ? message.suggestions : [];
208→      }
209→
210→      setInheritedMessageIds(inheritedIds);
211→      setSessions([
212→        {
213→          id: "main",
214→          title: workspaceName ?? "Workspace Chat",
215→          createdAt: new Date(),
216→          updatedAt: new Date(),
217→          conversations,
218→        },
219→      ]);
220→
221→      setSuggestions(
222→        latestSuggestions.map((content, index) => ({
223→          id: `conv-suggestion-${index}-${content}`,
224→          content,
225→        })),
226→      );
227→
228→      setActiveConversationId(conversationId);
229→      setBackendConversationId(conversationId);
230→      setConversationDiscussEntity(payload.discussEntity);
231→    } catch (error) {
232→      const messageText = error instanceof Error ? error.message : "Failed to load conversation";
233→      setErrorMessage(messageText);
234→    }
235→  }
236→
237→  function onNewConversation() {
238→    setActiveConversationId(undefined);
239→    setBackendConversationId(undefined);
240→    setSessions([
241→      {
242→        id: "main",
243→        title: workspaceName ?? "Workspace Chat",
244→        createdAt: new Date(),
245→        updatedAt: new Date(),
246→        conversations: [],
247→      },
248→    ]);
249→    setSuggestions([]);
250→    setErrorMessage(undefined);
251→    setConversationDiscussEntity(undefined);
252→    clearDiscussEntity();
253→  }
254→
255→  function onSelectConversation(conversationId: string) {
256→    if (conversationId === activeConversationId || isLoading || !workspaceId) {
257→      return;
258→    }
259→
260→    void loadConversation(workspaceId, conversationId);
261→  }
262→
263→  async function onBranchFromMessage(messageId: string) {
264→    if (!workspaceId || !activeConversationId || isLoading) return;
265→
266→    setBranchingFromId(messageId);
267→    try {
268→      const response = await fetch(
269→        `/api/workspaces/${encodeURIComponent(workspaceId)}/conversations/${encodeURIComponent(activeConversationId)}/branch`,
270→        {
271→          method: "POST",
272→          headers: { "Content-Type": "application/json" },
273→          body: JSON.stringify({ messageId }),
274→        },
275→      );
276→
277→      if (!response.ok) {
278→        const body = await response.text();
279→        setErrorMessage(body);
280→        return;
281→      }
282→
283→      const payload = (await response.json()) as BranchConversationResponse;
284→      await loadConversation(workspaceId, payload.conversationId);
285→      await refreshSidebar(workspaceId);
286→    } catch (error) {
287→      const messageText = error instanceof Error ? error.message : "Branch creation failed";
288→      setErrorMessage(messageText);
289→    } finally {
290→      setBranchingFromId(undefined);
291→    }
292→  }
293→
294→  async function searchMentions(query: string): Promise<MentionItem[]> {
295→    if (!workspaceId) {
296→      return [];
297→    }
298→
299→    const response = await fetch(
300→      `/api/entities/search?q=${encodeURIComponent(query)}&workspaceId=${encodeURIComponent(workspaceId)}&limit=8`,
301→    );
302→    if (!response.ok) {
303→      throw new Error(`entity search failed: ${response.status}`);
304→    }
305→
306→    const rows = (await response.json()) as SearchEntityResponse[];
307→    return rows.map((row) => ({
308→      id: row.id,
309→      label: `${row.kind}: ${row.text.slice(0, 48)}`,
310→      description: `confidence ${row.confidence.toFixed(2)}`,
311→      value: `@${row.id}`,
312→    }));
313→  }
314→
315→  function onUploadFile(file: File) {
316→    setPendingFile(file);
317→  }
318→
319→  function onChatInputClickCapture(event: MouseEvent<HTMLDivElement>) {
320→    if (!pendingFile || isLoading) {
321→      return;
322→    }
323→
324→    const target = event.target;
325→    if (!(target instanceof Element)) {
326→      return;
327→    }
328→
329→    const sendButton = target.closest("button[title='Send']");
330→    if (!sendButton) {
331→      return;
332→    }
333→
334→    const currentMessage = chatInputRef.current?.getValue().trim() ?? "";
335→    if (currentMessage.length > 0) {
336→      return;
337→    }
338→
339→    event.preventDefault();
340→    event.stopPropagation();
341→    void onSendMessage("");
342→  }
343→
344→  async function onSendMessage(
345→    message: string,
346→    options?: { onboardingAction?: OnboardingAction },
347→  ) {
348→    if (isLoading || !workspaceId) {
349→      return;
350→    }
351→
352→    const text = message.trim();
353→    if (!text && !pendingFile) {
354→      return;
355→    }
356→
357→    setErrorMessage(undefined);
358→    setIsLoading(true);
359→    setSuggestions([]);
360→
361→    const clientMessageId = crypto.randomUUID();
362→    const currentAttachment = pendingFile;
363→
364→    setSessions((existing) =>
365→      existing.map((session) =>
366→        session.id === activeSessionId
367→          ? {
368→              ...session,
369→              updatedAt: new Date(),
370→              conversations: [
371→                ...session.conversations,
372→                {
373→                  id: clientMessageId,
374→                  question: text.length > 0 ? text : `Uploaded ${currentAttachment?.name ?? "file"}`,
375→                  createdAt: new Date(),
376→                  ...(currentAttachment
377→                    ? {
378→                        files: [
379→                          {
380→                            name: currentAttachment.name,
381→                            type: currentAttachment.type,
382→                            size: currentAttachment.size,
383→                          },
384→                        ],
385→                      }
386→                    : {}),
387→                },
388→              ],
389→            }
390→          : session,
391→      ),
392→    );
393→
394→    let response: Response;
395→    try {
396→      const includeDiscussEntity = !backendConversationId && discussEntity;
397→
398→      if (currentAttachment) {
399→        const formData = new FormData();
400→        formData.set("clientMessageId", clientMessageId);
401→        formData.set("workspaceId", workspaceId);
402→        formData.set("text", text);
403→        if (backendConversationId) {
404→          formData.set("conversationId", backendConversationId);
405→        }
406→        if (options?.onboardingAction) {
407→          formData.set("onboardingAction", options.onboardingAction);
408→        }
409→        if (includeDiscussEntity) {
410→          formData.set("discussEntityId", discussEntity.id);
411→        }
412→        formData.set("file", currentAttachment);
413→
414→        response = await fetch("/api/chat/messages", {
415→          method: "POST",
416→          body: formData,
417→        });
418→      } else {
419→        response = await fetch("/api/chat/messages", {
420→          method: "POST",
421→          headers: {
422→            "Content-Type": "application/json",
423→          },
424→          body: JSON.stringify({
425→            clientMessageId,
426→            workspaceId,
427→            text,
428→            ...(backendConversationId ? { conversationId: backendConversationId } : {}),
429→            ...(options?.onboardingAction ? { onboardingAction: options.onboardingAction } : {}),
430→            ...(includeDiscussEntity ? { discussEntityId: discussEntity.id } : {}),
431→          }),
432→        });
433→      }
434→    } catch (error) {
435→      const messageText = error instanceof Error ? error.message : "Network error";
436→      setErrorMessage(messageText);
437→      setIsLoading(false);
438→      return;
439→    } finally {
440→      setPendingFile(undefined);
441→    }
442→
443→    if (!response.ok) {
444→      const body = await response.text();
445→      setErrorMessage(body);
446→      setIsLoading(false);
447→      return;
448→    }
449→
450→    const payload = (await response.json()) as ChatMessageResponse;
451→    const isNewConversation = !backendConversationId;
452→    setBackendConversationId(payload.conversationId);
453→    if (isNewConversation) {
454→      setActiveConversationId(payload.conversationId);
455→      if (discussEntity) {
456→        clearDiscussEntity();
457→      }
458→    }
459→
460→    if (streamRef.current) {
461→      streamRef.current.close();
462→      streamRef.current = undefined;
463→    }
464→
465→    let streamedText = "";
466→    let streamedReasoning = "";
467→
468→    const stream = new EventSource(payload.streamUrl);
469→    streamRef.current = stream;
470→
471→    stream.onmessage = (messageEvent) => {
472→      const parsed = JSON.parse(messageEvent.data) as ChatStreamEvent;
473→
474→      if (parsed.type === "reasoning") {
475→        streamedReasoning = `${streamedReasoning}${parsed.token}`;
476→        setReasoningByMessageId((prev) => new Map(prev).set(clientMessageId, streamedReasoning));
477→        return;
478→      }
479→
480→      if (parsed.type === "token") {
481→        streamedText = `${streamedText}${parsed.token}`;
482→        setSessions((existing) =>
483→          existing.map((session) =>
484→            session.id === activeSessionId
485→              ? {
486→                  ...session,
487→                  conversations: session.conversations.map((conversation) =>
488→                    conversation.id === clientMessageId
489→                      ? {
490→                          ...conversation,
491→                          response: streamedText,
492→                          updatedAt: new Date(),
493→                        }
494→                      : conversation,
495→                  ),
496→                }
497→              : session,
498→          ),
499→        );
500→        return;
501→      }
502→
503→      if (parsed.type === "extraction") {
504→        store.mergeSeedItems(
505→          parsed.entities.map((entity) => ({
506→            id: entity.id,
507→            kind: entity.kind,
508→            text: entity.text,
509→            confidence: entity.confidence,
510→            sourceKind: entity.sourceKind,
511→            sourceId: entity.sourceId,
512→          })),
513→        );
514→        return;
515→      }
516→
517→      if (parsed.type === "assistant_message") {
518→        streamedText = parsed.text;
519→        setSuggestions(
520→          (parsed.suggestions ?? []).map((content, index) => ({
521→            id: `suggestion-${parsed.messageId}-${index}-${content}`,
522→            content,
523→          })),
524→        );
525→        setSessions((existing) =>
526→          existing.map((session) =>
527→            session.id === activeSessionId
528→              ? {
529→                  ...session,
530→                  conversations: session.conversations.map((conversation) =>
531→                    conversation.id === clientMessageId
532→                      ? {
533→                          ...conversation,
534→                          response: streamedText,
535→                          updatedAt: new Date(),
536→                        }
537→                      : conversation,
538→                  ),
539→                }
540→              : session,
541→          ),
542→        );
543→        return;
544→      }
545→
546→      if (parsed.type === "onboarding_seed") {
547→        store.mergeSeedItems(parsed.seeds);
548→        return;
549→      }
550→
551→      if (parsed.type === "onboarding_state") {
552→        store.setOnboardingState(parsed.onboardingState);
553→        return;
554→      }
555→
556→      if (parsed.type === "error") {
557→        setErrorMessage(parsed.error);
558→        setIsLoading(false);
559→        stream.close();
560→        streamRef.current = undefined;
561→        return;
562→      }
563→
564→      if (parsed.type === "done") {
565→        setSessions((existing) =>
566→          existing.map((session) =>
567→            session.id === activeSessionId
568→              ? {
569→                  ...session,
570→                  updatedAt: new Date(),
571→                  conversations: session.conversations.map((conversation) =>
572→                    conversation.id === clientMessageId
573→                      ? {
574→                          ...conversation,
575→                          response: streamedText,
576→                          updatedAt: new Date(),
577→                        }
578→                      : conversation,
579→                  ),
580→                }
581→              : session,
582→          ),
583→        );
584→
585→        setIsLoading(false);
586→        stream.close();
587→        streamRef.current = undefined;
588→
589→        // Refresh sidebar after stream completes
590→        if (workspaceId) {
591→          void refreshSidebar(workspaceId);
592→        }
593→      }
594→    };
595→
596→    stream.onerror = () => {
597→      setErrorMessage("SSE stream disconnected");
598→      setIsLoading(false);
599→      stream.close();
600→      streamRef.current = undefined;
601→    };
602→  }
603→
604→  function onStopMessage() {
605→    if (!streamRef.current) {
606→      return;
607→    }
608→
609→    streamRef.current.close();
610→    streamRef.current = undefined;
611→    setIsLoading(false);
612→  }
613→
614→  return {
615→    sessions,
616→    activeSessionId,
617→    activeSession,
618→    activeConversationId,
619→    isLoading,
620→    errorMessage,
621→    suggestions,
622→    pendingFile,
623→    branchingFromId,
624→    inheritedMessageIds,
625→    discussEntity,
626→    conversationDiscussEntity,
627→    reasoningByMessageId,
628→    chatInputRef,
629→    onSendMessage,
630→    onStopMessage,
631→    onNewConversation,
632→    onSelectConversation,
633→    onBranchFromMessage,
634→    searchMentions,
635→    onUploadFile,
636→    onChatInputClickCapture,
637→    setErrorMessage,
638→    refreshSidebar,
639→  };
640→}
