      <EntityBadge kind={entity.kind as EntityKind} />
      <span className="discuss-entity-name">{entity.name}</span>
      {entity.status ? (
        <span className="discuss-entity-status">{entity.status}</span>
      ) : undefined}
    </div>
  );
}

