  1→import { useEffect, useRef, useState, type KeyboardEvent } from "react";
  2→import Markdown from "react-markdown";
  3→import { DiscussEntityCard } from "../components/chat/DiscussEntityCard";
  4→import { EntityLink } from "../components/chat/EntityLink";
  5→import type { DiscussEntitySummary } from "../../shared/contracts";
  6→import { useWorkspaceState } from "../stores/workspace-state";
  7→import { useChatSession } from "../hooks/use-chat-session";
  8→
  9→export function ChatPage() {
 10→  const onboardingState = useWorkspaceState((s) => s.onboardingState);
 11→  const setSidebarHandlers = useWorkspaceState((s) => s.setSidebarHandlers);
 12→
 13→  const chat = useChatSession();
 14→
 15→  // Keep a ref to the latest chat handlers so the effect below doesn't
 16→  // depend on unstable function references.
 17→  const chatRef = useRef(chat);
 18→  chatRef.current = chat;
 19→
 20→  // Register sidebar handlers so the shell sidebar can interact with chat
 21→  useEffect(() => {
 22→    setSidebarHandlers({
 23→      activeConversationId: chat.activeConversationId,
 24→      isLoading: chat.isLoading,
 25→      onNewConversation: () => chatRef.current.newConversation(),
 26→      onSelectConversation: (id: string) => chatRef.current.selectConversation(id),
 27→    });
 28→  }, [chat.activeConversationId, chat.isLoading]);
 29→
 30→  // Cleanup sidebar handlers on unmount
 31→  useEffect(() => {
 32→    return () => {
 33→      setSidebarHandlers(undefined);
 34→    };
 35→  }, []);
 36→
 37→  // Auto-scroll to bottom
 38→  const messagesEndRef = useRef<HTMLDivElement>(null);
 39→  useEffect(() => {
 40→    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
 41→  }, [chat.messages]);
 42→
 43→  return (
 44→    <section className="chat-page">
 45→      {(chat.discussEntity ?? chat.conversationDiscussEntity) ? (
 46→        <DiscussEntityCard
 47→          entity={(chat.discussEntity ?? chat.conversationDiscussEntity) as DiscussEntitySummary}
 48→        />
 49→      ) : undefined}
 50→
 51→      <div className="chat-messages">
 52→        {chat.messages.map((message) => (
 53→          <div
 54→            key={message.id}
 55→            data-message-id={message.id}
 56→            className={`chat-message chat-message--${message.role}`}
 57→          >
 58→            {message.role === "user" ? (
 59→              <div className="chat-message-label">You</div>
 60→            ) : undefined}
 61→            {message.parts.map((part, i) => {
 62→              if (part.type === "text") {
 63→                return (
 64→                  <div key={i} className="chat-message-text">
 65→                    <Markdown components={{ a: EntityLink }}>{part.text}</Markdown>
 66→                  </div>
 67→                );
 68→              }
 69→              if (part.type === "reasoning") {
 70→                return (
 71→                  <details key={i} className="thinking-block">
 72→                    <summary>Thinking</summary>
 73→                    <pre className="thinking-content">{part.text}</pre>
 74→                  </details>
 75→                );
 76→              }
 77→              if (isToolPart(part)) {
 78→                const toolPart = part as { type: string; state: string };
 79→                return (
 80→                  <div key={i} className="chat-tool-invocation">
 81→                    <span className="chat-tool-name">{toolPart.type.replace(/^tool-/, "")}</span>
 82→                    {toolPart.state === "output-available" ? (
 83→                      <span className="chat-tool-status">Done</span>
 84→                    ) : (
 85→                      <span className="chat-tool-status chat-tool-status--running">Running...</span>
 86→                    )}
 87→                  </div>
 88→                );
 89→              }
 90→              return undefined;
 91→            })}
 92→            {message.role === "assistant" && onboardingState === "complete" ? (
 93→              <button
 94→                type="button"
 95→                className="branch-message-btn"
 96→                onClick={() => void chat.branchFromMessage(message.id)}
 97→                disabled={chat.isLoading || chat.branchingFromId !== undefined}
 98→                title="Branch from here"
 99→              >
100→                <svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
101→                  <path d="M5 3v4.5c0 1.1.9 2 2 2h2.5M5 3L3 5M5 3l2 2M11 5v4.5c0 1.1-.9 2-2 2H6.5M11 5l-2-2M11 5l2-2" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
102→                </svg>
103→              </button>
104→            ) : undefined}
105→          </div>
106→        ))}
107→        <div ref={messagesEndRef} />
108→      </div>
109→
110→      {onboardingState === "summary_pending" ? (
111→        <div className="onboarding-action-buttons">
112→          <button
113→            type="button"
114→            disabled={chat.isLoading}
115→            onClick={() =>
116→              chat.sendMessage("Looks good, let's go.", {
117→                onboardingAction: "finalize_onboarding",
118→              })}
119→          >
120→            Looks good, let's go
121→          </button>
122→          <button
123→            type="button"
124→            disabled={chat.isLoading}
125→            onClick={() =>
126→              chat.sendMessage("I want to add more.", {
127→                onboardingAction: "continue_onboarding",
128→              })}
129→          >
130→            I want to add more
131→          </button>
132→        </div>
133→      ) : undefined}
134→
135→      <ChatInput
136→        onSend={chat.sendMessage}
137→        disabled={chat.isLoading}
138→        onStop={chat.stopMessage}
139→        isStreaming={chat.status === "streaming"}
140→      />
141→
142→      {chat.errorMessage ? <p className="error-message">{chat.errorMessage}</p> : undefined}
143→    </section>
144→  );
145→}
146→
147→function isToolPart(part: { type: string }): boolean {
148→  return part.type.startsWith("tool-");
149→}
150→
151→function ChatInput({
152→  onSend,
153→  disabled,
154→  onStop,
155→  isStreaming,
156→}: {
157→  onSend: (text: string) => void;
158→  disabled: boolean;
159→  onStop: () => void;
160→  isStreaming: boolean;
161→}) {
162→  const [input, setInput] = useState("");
163→  const textareaRef = useRef<HTMLTextAreaElement>(null);
164→
165→  function handleSubmit() {
166→    const trimmed = input.trim();
167→    if (!trimmed || disabled) return;
168→    onSend(trimmed);
169→    setInput("");
170→    // Reset textarea height
171→    if (textareaRef.current) {
172→      textareaRef.current.style.height = "auto";
173→    }
174→  }
175→
176→  function handleKeyDown(e: KeyboardEvent<HTMLTextAreaElement>) {
177→    if (e.key === "Enter" && !e.shiftKey) {
178→      e.preventDefault();
179→      handleSubmit();
180→    }
181→  }
182→
183→  // Auto-resize textarea
184→  useEffect(() => {
185→    const textarea = textareaRef.current;
186→    if (!textarea) return;
187→    textarea.style.height = "auto";
188→    textarea.style.height = `${Math.min(textarea.scrollHeight, 200)}px`;
189→  }, [input]);
190→
191→  return (
192→    <div className="chat-input-container">
193→      <textarea
194→        ref={textareaRef}
195→        className="chat-input"
196→        value={input}
197→        onChange={(e) => setInput(e.target.value)}
198→        onKeyDown={handleKeyDown}
199→        placeholder="Discuss tasks, decisions, and questions..."
200→        rows={1}
201→        disabled={disabled && !isStreaming}
202→      />
203→      {isStreaming ? (
204→        <button
205→          type="button"
206→          className="chat-input-btn chat-input-btn--stop"
207→          onClick={onStop}
208→          title="Stop"
209→        >
210→          Stop
211→        </button>
212→      ) : (
213→        <button
214→          type="button"
215→          className="chat-input-btn chat-input-btn--send"
216→          onClick={handleSubmit}
217→          disabled={disabled || input.trim().length === 0}
218→          title="Send"
219→        >
220→          Send
221→        </button>
222→      )}
223→    </div>
224→  );
225→}
